@app.route('/api/verify_payment', methods=['POST'])
def verify_payment():
    data = request.json
    try:
        # Verify the signature
        params_dict = {
            'razorpay_order_id': data['razorpay_order_id'],
            'razorpay_payment_id': data['razorpay_payment_id'],
            'razorpay_signature': data['razorpay_signature']
        }
        razorpay_client.utility.verify_payment_signature(params_dict)
        
        # Payment verified securely
        # TODO: Here we would trigger a Supabase DB UPDATE to set user_profiles.plan_type = 'pro'
        
        return jsonify({'status': 'success', 'message': 'Payment verified successfully! Welcome to Eureka Pro!'})
    except razorpay.errors.SignatureVerificationError:
        return jsonify({'status': 'failure', 'message': 'Payment signature verification failed. Possible tampering.'}), 400
    except Exception as e:
        return jsonify({'status': 'error', 'message': str(e)}), 500

@app.route('/api/create_hotel_booking', methods=['POST'])
def create_hotel_booking():
    if not razorpay_client:
        return jsonify({'error': 'Payment gateway not configured on server (Missing Keys)'}), 500
        
    try:
        data = request.json
        # Convert supplied price to proper integer amount in paise (default to 2000 INR if invalid)
        try:
            price_in_inr = int(float(str(data.get('price', 2000)).replace(',', '')))
        except ValueError:
            price_in_inr = 2000
            
        hotel_name = data.get('hotel_name', 'Eureka Accommodations')
        
        order_data = {
            'amount': price_in_inr * 100, # amount in PAISE
            'currency': 'INR',
            'receipt': 'booking_' + os.urandom(3).hex(),
            'payment_capture': 1
        }
        order = razorpay_client.order.create(data=order_data)
        
        return jsonify({
            'order_id': order['id'],
            'amount': order['amount'],
            'currency': order['currency'],
            'key': RAZORPAY_KEY_ID,
            'hotel_name': hotel_name
        })
    except Exception as e:
        logging.error(f"Razorpay Hotel Order Error: {e}")
        return jsonify({'error': str(e)}), 500

